test_cases.python_test_script:
def test_tc_gw_turn_per_005_constant_state(can_bus):
    msgs = collect_gateway_messages(can_bus, 3.0)
    assert len(msgs) >= EXPECTED_MIN_MESSAGES
    states = {decode_turn_active(m.data) for m in msgs}
    assert len(states) == 1

def test_tc_gw_turn_per_007_no_message_loss(can_bus):
    msgs = collect_gateway_messages(can_bus, 5.0)
    assert len(msgs) >= EXPECTED_MIN_MESSAGES
    for msg in msgs:
        assert decode_turn_active(msg.data) in (0, 1)
